'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Package, Eye, EyeOff, Phone, Lock } from 'lucide-react'
import { livreurAuthService } from '@/lib/services/livreurAuthService'
import { formatUserError } from '@/lib/errors'
import { useToast } from '@/contexts/ToastContext'
import { DEMO_MODE } from '@/lib/config'

export default function LivreurLoginPage() {
  const router = useRouter()
  const { error: toastError } = useToast()
  const [phone, setPhone] = useState('')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [loading, setLoading] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!phone.trim() || !password.trim()) return
    setLoading(true)
    try {
      await livreurAuthService.login(phone.trim(), password)
      router.replace('/livreur')
    } catch (err) {
      toastError(formatUserError(err, 'Connexion impossible. Vérifiez votre numéro et votre mot de passe.'))
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="flex flex-col min-h-screen bg-orange-500">

      {/* ── Hero orange ── */}
      <div className="px-6 pt-14 pb-20 flex-shrink-0">
        {/* Logo */}
        <div className="flex items-center gap-3 mb-10">
          <div className="w-11 h-11 rounded-2xl bg-white/20 backdrop-blur-sm flex items-center justify-center">
            <Package size={22} className="text-white" />
          </div>
          <div>
            <p className="text-[10px] font-semibold text-white/60 tracking-widest uppercase">TiiBnTick Agency</p>
            <p className="text-base font-bold text-white leading-tight">Espace Livreur</p>
          </div>
        </div>

        {/* Headline */}
        <h1 className="text-3xl font-bold text-white leading-tight mb-2">
          Bonjour,<br />connectez-vous
        </h1>
        <p className="text-sm text-white/70">
          Accédez à vos missions et votre tableau de bord.
        </p>
      </div>

      {/* ── White card ── */}
      <div className="flex-1 bg-white rounded-t-3xl -mt-6 px-6 pt-8 pb-10">

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Phone */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wide">
              Numéro de téléphone
            </label>
            <div className="relative">
              <Phone size={15} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
              <input
                type="tel"
                value={phone}
                onChange={e => setPhone(e.target.value)}
                placeholder="+237 6XX XX XX XX"
                autoComplete="tel"
                className="w-full h-13 pl-11 pr-4 py-3.5 text-sm bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-400 focus:border-transparent focus:bg-white transition-colors"
                required
              />
            </div>
          </div>

          {/* Password */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wide">
              Mot de passe
            </label>
            <div className="relative">
              <Lock size={15} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
              <input
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Votre mot de passe"
                autoComplete="current-password"
                className="w-full h-13 pl-11 pr-12 py-3.5 text-sm bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-400 focus:border-transparent focus:bg-white transition-colors"
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(v => !v)}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 p-0.5"
                tabIndex={-1}
              >
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={loading || !phone.trim() || !password.trim()}
            className="w-full h-13 py-3.5 bg-orange-500 hover:bg-orange-600 active:bg-orange-700 disabled:bg-orange-200 text-white text-sm font-bold rounded-xl transition-colors flex items-center justify-center mt-2 shadow-sm shadow-orange-200"
          >
            {loading
              ? <span className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
              : 'Se connecter'
            }
          </button>
        </form>

        {/* Demo hint */}
        {!DEMO_MODE && (
          <div className="mt-8 rounded-2xl border border-gray-200 bg-gray-50 p-4">
            <p className="text-[11px] font-bold text-gray-600 uppercase tracking-wider mb-2">Mode live</p>
            <p className="text-xs text-gray-500">
              Connectez-vous avec votre numéro de téléphone enregistré par l&apos;agence
              (onglet Personnel → Livreurs).
              Mot de passe : <span className="font-semibold">livreur1234</span>
            </p>
          </div>
        )}
        {DEMO_MODE && (
          <div className="mt-8 rounded-2xl border border-orange-100 bg-orange-50 p-4">
            <p className="text-[11px] font-bold text-orange-600 uppercase tracking-wider mb-3">Comptes de démo</p>
            <div className="space-y-2.5">
              <DemoAccount
                label="Disponible"
                phone="+237 691 23 45 67"
                name="Jean-Paul Essomba"
                onFill={() => { setPhone('+237 691 23 45 67'); setPassword('livreur1234') }}
              />
              <DemoAccount
                label="En mission"
                phone="+237 677 89 01 23"
                name="Martin Mbarga"
                onFill={() => { setPhone('+237 677 89 01 23'); setPassword('livreur1234') }}
              />
            </div>
            <p className="text-[11px] text-orange-500 mt-3">Mot de passe : <span className="font-mono font-semibold">livreur1234</span></p>
          </div>
        )}
      </div>
    </div>
  )
}

function DemoAccount({ label, phone, name, onFill }: {
  label: string; phone: string; name: string; onFill: () => void
}) {
  return (
    <button
      type="button"
      onClick={onFill}
      className="w-full flex items-center justify-between bg-white rounded-xl px-3 py-2.5 border border-orange-100 hover:border-orange-300 transition-colors text-left"
    >
      <div>
        <p className="text-xs font-semibold text-gray-700">{name}</p>
        <p className="text-[11px] text-gray-400 font-mono">{phone}</p>
      </div>
      <span className="text-[10px] font-semibold text-orange-500 bg-orange-50 px-2 py-0.5 rounded-full">{label}</span>
    </button>
  )
}
