import { formatUserError } from '@/lib/errors';
import {
  DEMO_MODE,
  DEMO_AGENCY_ID,
  DEMO_TENANT_ID,
  API_BASE_URL,
} from '@/lib/config';
import { mapDeliverer, mapMission } from '@/lib/api/mappers';
import type { DelivererDto, MissionDto } from '@/lib/api/dto';
import type { Deliverer, Mission } from '@/lib/types';
import { mockDeliverers, mockMissions } from '@/lib/mock-data';

const DEMO_PASSWORD = 'livreur1234';
const DEMO_TOKEN = 'demo-livreur-jwt';

export interface LivreurSession {
  token: string;
  delivererId: string;
  delivererName: string;
  tenantId: string;
  agencyId: string;
}

function saveSession(s: LivreurSession) {
  localStorage.setItem('tnt-livreur-token', s.token);
  localStorage.setItem('tnt-livreur-id', s.delivererId);
  localStorage.setItem('tnt-livreur-name', s.delivererName);
  localStorage.setItem('tnt-livreur-tenant-id', s.tenantId);
  localStorage.setItem('tnt-livreur-agency-id', s.agencyId);
}

function clearSession() {
  localStorage.removeItem('tnt-livreur-token');
  localStorage.removeItem('tnt-livreur-id');
  localStorage.removeItem('tnt-livreur-name');
  localStorage.removeItem('tnt-livreur-tenant-id');
  localStorage.removeItem('tnt-livreur-agency-id');
}

function getLivreurHeaders(): Record<string, string> {
  const token = typeof window !== 'undefined' ? localStorage.getItem('tnt-livreur-token') ?? '' : '';
  const tenantId = typeof window !== 'undefined'
    ? localStorage.getItem('tnt-livreur-tenant-id') ?? DEMO_TENANT_ID
    : DEMO_TENANT_ID;
  const agencyId = typeof window !== 'undefined'
    ? localStorage.getItem('tnt-livreur-agency-id') ?? DEMO_AGENCY_ID
    : DEMO_AGENCY_ID;
  return {
    'Content-Type': 'application/json',
    'X-Tenant-Id': tenantId,
    'X-Agency-Id': agencyId,
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };
}

async function livreurFetch<T>(path: string, options: RequestInit = {}): Promise<T> {
  const normalized = path.startsWith('/') ? path : `/${path}`;
  let res: Response;
  try {
    res = await fetch(`${API_BASE_URL}${normalized}`, {
      ...options,
      headers: { ...getLivreurHeaders(), ...(options.headers as Record<string, string> | undefined) },
    });
  } catch {
    throw new Error(formatUserError(null, 'Impossible de joindre le serveur. Vérifiez votre connexion.'));
  }
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(formatUserError(
      { status: res.status, message: body?.message ?? '' },
      'Une erreur est survenue. Réessayez dans un instant.',
    ));
  }
  if (res.status === 204) return undefined as T;
  return res.json() as Promise<T>;
}

export const livreurAuthService = {
  async login(phone: string, password: string): Promise<LivreurSession> {
    if (DEMO_MODE) {
      await new Promise(r => setTimeout(r, 700));
      const deliverer = mockDeliverers.find(d => d.phone === phone);
      if (!deliverer || password !== DEMO_PASSWORD) {
        throw new Error('Numéro de téléphone ou mot de passe incorrect.');
      }
      const session: LivreurSession = {
        token: DEMO_TOKEN,
        delivererId: deliverer.id,
        delivererName: deliverer.fullName,
        tenantId: DEMO_TENANT_ID,
        agencyId: DEMO_AGENCY_ID,
      };
      saveSession(session);
      return session;
    }

    const data = await livreurFetch<{
      accessToken: string;
      tenantId: string;
      agencyId: string;
      delivererId: string;
      delivererName: string;
    }>('/auth/livreur/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'X-Tenant-Id': DEMO_TENANT_ID },
      body: JSON.stringify({
        phone,
        password,
        tenantId: DEMO_TENANT_ID,
        agencyId: DEMO_AGENCY_ID,
      }),
    });

    const session: LivreurSession = {
      token: data.accessToken,
      delivererId: data.delivererId,
      delivererName: data.delivererName,
      tenantId: data.tenantId,
      agencyId: data.agencyId,
    };
    saveSession(session);
    return session;
  },

  logout() {
    clearSession();
    window.location.href = '/livreur/login';
  },

  isAuthenticated(): boolean {
    return !!localStorage.getItem('tnt-livreur-token');
  },

  getCurrentDelivererId(): string | null {
    return localStorage.getItem('tnt-livreur-id');
  },

  getCurrentDelivererName(): string | null {
    return localStorage.getItem('tnt-livreur-name');
  },
};

export const livreurMissionService = {
  async getMyMissions(delivererId: string): Promise<Mission[]> {
    if (DEMO_MODE) return mockMissions.filter(m => m.delivererId === delivererId);
    const dtos = await livreurFetch<MissionDto[]>(`/deliverers/${delivererId}/missions`);
    return dtos.map(mapMission);
  },

  async getMission(missionId: string): Promise<Mission> {
    if (DEMO_MODE) {
      const m = mockMissions.find(x => x.id === missionId);
      if (!m) throw new Error('Mission introuvable');
      return m;
    }
    const dto = await livreurFetch<MissionDto>(`/missions/${missionId}`);
    return mapMission(dto);
  },

  async getMyProfile(delivererId: string): Promise<Deliverer> {
    if (DEMO_MODE) {
      const d = mockDeliverers.find(x => x.id === delivererId);
      if (!d) throw new Error('Profil introuvable');
      return d;
    }
    const dto = await livreurFetch<DelivererDto>(`/deliverers/${delivererId}`);
    return mapDeliverer(dto);
  },

  async confirmPickup(missionId: string): Promise<void> {
    if (DEMO_MODE) return;
    const delivererId = livreurAuthService.getCurrentDelivererId();
    if (!delivererId) throw new Error('Session expirée');
    await livreurFetch(`/missions/${missionId}/pickup`, {
      method: 'POST',
      body: JSON.stringify({ delivererId }),
    });
  },

  async confirmDelivery(missionId: string): Promise<void> {
    if (DEMO_MODE) return;
    const delivererId = livreurAuthService.getCurrentDelivererId();
    if (!delivererId) throw new Error('Session expirée');
    await livreurFetch(`/missions/${missionId}/deliver`, {
      method: 'POST',
      body: JSON.stringify({ delivererId, proofReference: `POD-${Date.now()}` }),
    });
  },

  async reportIssue(missionId: string, reason: string): Promise<void> {
    if (DEMO_MODE) return;
    const delivererId = livreurAuthService.getCurrentDelivererId();
    if (!delivererId) throw new Error('Session expirée');
    await livreurFetch(`/missions/${missionId}/anomaly`, {
      method: 'POST',
      body: JSON.stringify({
        delivererId,
        anomalyType: 'OTHER',
        description: reason,
        fatal: false,
      }),
    });
  },
};
